mapper.sql:
from t_waybill w
left join t_order o on w.order_id = o.order_id
LEFT JOIN t_vehicle v ON v.vehicle_id = w.vehicle_id
LEFT JOIN t_shipper s ON s.shipper_id = w.shipper_id


    ( INSTR(w.waybill_number,#{queryForm.keywords})
    or INSTR(o.order_no,#{queryForm.keywords})
    or INSTR(w.container_number,#{queryForm.keywords})
    or INSTR(w.lead_seal_number,#{queryForm.keywords})
    or INSTR(w.create_user_name,#{queryForm.keywords})
    or INSTR(s.short_name,#{queryForm.keywords})
    or INSTR(s.consignor,#{queryForm.keywords})
    )


        AND INSTR(w.waybill_number,#{queryForm.waybillNumber})


        AND INSTR(o.order_no,#{queryForm.orderNo})


        AND INSTR(o.shipper_order_number,#{queryForm.shipperOrderNumber})


        AND INSTR(w.container_number,#{queryForm.containerNumber})


        AND INSTR(w.lead_seal_number,#{queryForm.leadSealNumber})


        AND w.pay_status = #{queryForm.payStatus}


        AND o.cabinet_id = #{queryForm.cabinetId}


        and DATE_FORMAT(o.latest_packing_time, '%Y-%m-%d') >= #{queryForm.latestPackingTimeStart}


        and DATE_FORMAT(o.latest_packing_time, '%Y-%m-%d') <= #{queryForm.latestPackingTimeEnd}


        AND INSTR(o.container_location,#{queryForm.containerLocation})


        AND INSTR(o.placing_location,#{queryForm.placingLocation})


        AND INSTR(o.unloading_location,#{queryForm.unloadingLocation})


        AND INSTR(o.return_container_location,#{queryForm.returnContainerLocation})


        and w.audit_status = #{queryForm.auditStatus}


        and DATE_FORMAT(w.deliver_goods_time, '%Y-%m-%d') >= #{queryForm.deliverGoodsTimeStart}


        and DATE_FORMAT(w.deliver_goods_time, '%Y-%m-%d') <= #{queryForm.deliverGoodsTimeEnd}


        and DATE_FORMAT(w.receive_goods_time, '%Y-%m-%d') >= #{queryForm.receiveGoodsTimeStart}


        and DATE_FORMAT(w.receive_goods_time, '%Y-%m-%d') <= #{queryForm.receiveGoodsTimeEnd}


        AND w.waybill_id IN

            #{item}



        and w.waybill_number IN

            #{item}



        AND w.split_transport_flag = #{queryForm.splitTransportFlag}


        AND w.profit_amount >= #{queryForm.startProfitAmount}


        AND w.profit_amount <= #{queryForm.endProfitAmount}


        AND w.shipper_id = #{queryForm.shipperId}


        AND w.driver_id = #{queryForm.driverId}


        AND w.vehicle_id = #{queryForm.vehicleId}


        AND v.vehicle_type = #{queryForm.vehicleType}


        and v.business_mode IN

            #{item}



        AND w.fleet_id = #{queryForm.fleetId}


        AND w.order_type = #{queryForm.orderType}


        AND w.settle_type = #{queryForm.settleType}


        AND w.submit_pay_flag = #{queryForm.submitPayFlag}


        AND w.submit_receive_flag = #{queryForm.submitReceiveFlag}


        AND w.waybill_status != #{queryForm.excludeStatus}


        and w.waybill_status = #{queryForm.waybillStatus}


        and DATE_FORMAT(w.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        and DATE_FORMAT(w.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        and w.enterprise_id = #{queryForm.enterpriseId}


        and w.settle_mode = #{queryForm.settleMode}


        AND o.manager_id IN

            #{item}



        and w.create_user_id IN

            #{item}



        and w.transport_mode = #{queryForm.transportMode}


        AND w.waybill_id IN (
        SELECT DISTINCT waybill_id FROM t_waybill_exception
        WHERE exception_type IN

            #{item}

        AND deleted_flag = 0
        )


        and DATE_FORMAT(w.load_time, '%Y-%m-%d') >= #{queryForm.startLoadTime}


        and DATE_FORMAT(w.load_time, '%Y-%m-%d') <= #{queryForm.endLoadTime}


        and DATE_FORMAT(w.business_date, '%Y-%m-01') >= date_format(#{queryForm.businessStartDate},'%Y-%m-01')


        and DATE_FORMAT(w.business_date, '%Y-%m-01') <= date_format(#{queryForm.businessEndDate},'%Y-%m-01')


        and (
        w.driver_id IN

            #{item}

        or
        w.waybill_id IN (
            SELECT wst.waybill_id FROM t_waybill_split_transport wst
            WHERE wst.driver_id IN

                #{item}

            )
        )


        and w.vehicle_id IN

            #{item}



        and o.schedule_id IN

            #{item}



        and o.create_user_id IN

            #{item}



        and DATE_FORMAT(w.deliver_goods_time, '%Y-%m-%d') >= #{queryForm.deliverGoodsStartTime}


        and DATE_FORMAT(w.deliver_goods_time, '%Y-%m-%d') <= #{queryForm.deliverGoodsEndTime}



    order by w.waybill_id desc

