select w.*, o.order_no, o.remark orderRemark, o.business_type_code, o.container_business_type_id, o.container_location, o.placing_location, o.unloading_location, o.return_container_location, o.tax_point, o.cabinet_id, o.manager_id as orderManagerId, o.create_user_id orderCreateUserId, o.create_user_name orderCreateUserName from t_waybill w left join t_order o on w.order_id = o.order_id where w.order_id = #{orderId}
and w.waybill_status IN
#{item}
order by w.waybill_id desc

