SELECT shipper_id, DATE_FORMAT( create_time, '%Y-%m' ) month, COUNT( 1 ) count FROM t_waybill WHERE waybill_status != #{queryForm.excludeStatus} AND DATE_FORMAT( create_time, '%Y' ) = #{queryForm.year} AND shipper_id IN
#{item}
GROUP BY shipper_id, DATE_FORMAT( create_time, '%Y-%m' )

select w.shipper_id, s.consignor, s.short_name, s.disable_flag from t_waybill w left join t_shipper s on w.shipper_id = s.shipper_id where w.waybill_status != #{queryForm.excludeStatus}
AND ( INSTR(s.consignor,#{queryForm.keywords}) or INSTR(s.short_name,#{queryForm.keywords}) )
AND s.enterprise_id = #{queryForm.enterpriseId}
group by w.shipper_id

SELECT DATE_FORMAT( create_time, '%Y-%m' ) month, COUNT( 1 ) count FROM t_waybill WHERE waybill_status != #{excludeStatus} AND DATE_FORMAT( create_time, '%Y' ) = #{year}
AND shipper_id in
#{item}
GROUP BY DATE_FORMAT( create_time, '%Y-%m' )

SELECT COUNT(1) FROM t_waybill
where driver_id = #{driverId} AND nft_enterprise_id IS NOT NULL AND enterprise_id != #{excludeEnterpriseId}
