SELECT o.manager_id employeeId, SUM(w.receive_amount ) receive_amount, SUM(w.payable_amount) payableAmount, IFNULL(SUM(w.salary_amount),0) salaryAmount, IFNULL(SUM(w.car_cost_amount),0) carCostAmount, ROUND(SUM(w.receive_amount / (100 + w.tax_point) * w.tax_point),2) taxAmount FROM t_waybill w LEFT JOIN t_order o ON o.order_id = w.order_id WHERE waybill_status != #{queryForm.excludeStatus} AND date_format(w.business_date,'%Y-%m-01') = #{queryForm.queryDate} AND o.manager_id in
#{item}
GROUP BY o.manager_id

SELECT o.create_user_id employeeId, o.create_user_name employeeName, SUM( w.receive_amount ) receiveAmount, SUM( w.payable_amount ) payableAmount , IFNULL(SUM(w.salary_amount),0) salaryAmount, IFNULL(SUM(w.car_cost_amount),0) carCostAmount, ROUND(SUM(w.receive_amount / (100 + w.tax_point) * w.tax_point),2) taxAmount FROM t_waybill w left join t_order o on o.order_id = w.order_id
waybill_status != #{queryForm.excludeStatus} AND date_format(w.business_date,'%Y-%m-01') = #{queryForm.queryDate}
AND o.create_user_id in
#{item}
GROUP BY o.create_user_id

