mapper.select:
SELECT e.actual_name AS employeeName, SUM(w.receive_amount) AS receiveAmount FROM t_waybill w LEFT JOIN t_order o ON w.order_id = o.order_id LEFT JOIN t_employee e ON o.manager_id = e.employee_id WHERE o.deleted_flag=#{queryForm.deletedFlag} AND w.order_id IS NOT NULL
AND e.employee_id IN
#{item}
AND w.enterprise_id = #{queryForm.enterpriseId}
AND DATE_FORMAT(w.business_date, '%Y-%m-01') >= DATE_FORMAT(#{queryForm.businessStartDate}, '%Y-%m-01')
AND DATE_FORMAT(w.business_date, '%Y-%m-01') <= DATE_FORMAT(#{queryForm.businessEndDate}, '%Y-%m-01')
AND o.`status` != #{queryForm.orderStatus}
GROUP BY o.manager_id;

SELECT o.create_user_id AS employeeId,
o.create_user_name AS employeeName,
mbt.trip_type,
DATE_FORMAT(w.load_time,'%Y-%m-%d') loadTime,
COUNT(1) AS waybillCount
FROM t_waybill w
LEFT JOIN t_order o ON o.order_id = w.order_id
LEFT JOIN t_material_business_type mbt ON o.container_business_type_id = mbt.business_type_id
WHERE o.status != #{queryForm.excludeOrderStatus} AND w.waybill_status != #{queryForm.excludeWaybillStatus}

    AND w.enterprise_id = #{queryForm.enterpriseId}


    AND o.create_user_id IN

        #{id}



    AND mbt.trip_type IN

        #{id}



    AND DATE_FORMAT(w.load_time, '%Y-%m-%d') >= #{queryForm.startLoadTime}


    AND DATE_FORMAT(w.load_time, '%Y-%m-%d') <= #{queryForm.endLoadTime}

GROUP BY o.create_user_id, mbt.trip_type, DATE_FORMAT(w.load_time,'%Y-%m-%d')
ORDER BY o.create_user_id

