       s.consignor,
       s.enterprise_id,
       COUNT(1) waybillCount,
       SUM(w.receive_amount) receiveAmount,
       SUM(w.salary_amount) salaryAmount,
       SUM(w.car_cost_amount) carCostAmount,
       SUM(w.profit_amount) profitAmount
